<span class="line">mitt<span class="token punctuation">.</span><span class="token function">on</span><span class="token punctuation">(</span><span class="token string">&#39;handleChange&#39;</span><span class="token punctuation">,</span>someMethed<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
